import React from "react";

export const CinemaCard = ({ cinema, onUpdate, onDelete, onViewDetails }) => {
  const handleUpdate = (e) => {
    e.preventDefault();
    onUpdate(cinema);
  };

  const handleDelete = (e) => {
    e.preventDefault();
    if (window.confirm(`Are you sure you want to delete ${cinema.cinema_name}?`)) {
      onDelete(cinema._id);
    }
  };

  const handleViewDetails = (e) => {
    e.preventDefault();
    onViewDetails(cinema);
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const getMovieCount = () => {
    const ongoingMovies = cinema.ongoing_movies || {};
    const upcomingMovies = cinema.upcoming_movies || {};
    return Object.keys(ongoingMovies).length + Object.keys(upcomingMovies).length;
  };

  return (
    <div className="blog-card">
      <div className="meta">
        <div 
          className="photo" 
          style={{ 
            backgroundImage: `url(${cinema.image || '/images/cinema.jpg'})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center'
          }} 
        />
        <ul className="details">
          <li className="author">
            <button 
              className="cinema-name-link"
              onClick={handleViewDetails}
              style={{
                background: 'none',
                border: 'none',
                color: 'inherit',
                textDecoration: 'underline',
                cursor: 'pointer',
                padding: 0,
                font: 'inherit'
              }}
            >
              {cinema.cinema_name}
            </button>
          </li>
          <li className="date">{formatDate(cinema.createdAt)}</li>
          <li className="tags">
            <ul>
              <li><span className="tag">{cinema.cinema_location}</span></li>
              <li><span className="tag">{getMovieCount()} Movies</span></li>
            </ul>
          </li>
        </ul>
      </div>
      <div className="description">
        <h1>{cinema.cinema_name}</h1>
        <h2>{cinema.cinema_location}</h2>
        <p>
          {cinema.description || 'A premium cinema experience with state-of-the-art facilities and comfortable seating.'}
        </p>
        <div className="cinema-stats">
          <div className="stat">
            <strong>{Object.keys(cinema.ongoing_movies || {}).length}</strong>
            <span>Ongoing Movies</span>
          </div>
          <div className="stat">
            <strong>{Object.keys(cinema.upcoming_movies || {}).length}</strong>
            <span>Upcoming Movies</span>
          </div>
        </div>
        <div className="card-actions">
          <button 
            className="btn btn-primary btn-sm"
            onClick={handleUpdate}
          >
            <i className="fa fa-edit"></i>
            Edit
          </button>
          <button 
            className="btn btn-danger btn-sm"
            onClick={handleDelete}
          >
            <i className="fa fa-trash"></i>
            Delete
          </button>
        </div>
      </div>
    </div>
  );
};
